  `pdf` varchar(250) NOT NULL,
  `created_at` datetime DEFAULT NULL COMMENT 'Fecha de creación del registro',
  `updated_at` datetime DEFAULT NULL COMMENT 'Fecha de actualización del registro',
  `active` int DEFAULT '0' COMMENT 'Activo:\\n0 - No\\n1 - Sí'
